// FUNCIONES PARA IMPRIMIR Y DESCARGAR PDF DE REMISIONES
// ═══════════════════════════════════════════════════════════

function compartirRemision() {
  var element = document.getElementById('remision-print');
  if (!element) { showAdminToast('No hay remision para compartir'); return; }
  if (!navigator.share) { showAdminToast('Dispositivo no soporta compartir'); return; }
  if (typeof html2pdf === 'undefined') { showAdminToast('❌ Error: Biblioteca html2pdf no cargada'); return; }
  showAdminToast('Preparando PDF...');
  var btns = document.querySelectorAll('.no-print');
  btns.forEach(function(b) { b.style.display = 'none'; });
  element.style.minHeight = '277mm';
  element.style.display = 'flex';
  element.style.flexDirection = 'column';
  var firmas = element.querySelector('.firmas-block');
  if (firmas) firmas.style.marginTop = 'auto';
  var opt = {
    margin: [10, 10, 10, 10],
    filename: 'remision.pdf',
    image: { type: 'jpeg', quality: 0.98 },
    html2canvas: { scale: 2, useCORS: true, logging: false, onclone: function(doc) { if (window.innerWidth < 800) { var ce = doc.getElementById('remision-print'); if (ce) { ce.style.width = '794px'; ce.style.maxWidth = '794px'; ce.style.minHeight = '277mm'; ce.style.display = 'flex'; ce.style.flexDirection = 'column'; var cf = ce.querySelector('.firmas-block'); if (cf) cf.style.marginTop = 'auto'; } } } },
    jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
  };
  html2pdf().set(opt).from(element).outputPdf('blob').then(function(blob) {
    btns.forEach(function(b) { b.style.display = ''; });
    element.style.minHeight = '';
    element.style.display = '';
    element.style.flexDirection = '';
    if (firmas) firmas.style.marginTop = '';
    var file = new File([blob], 'remision.pdf', { type: 'application/pdf' });
    var data = (navigator.canShare && navigator.canShare({ files: [file] }))
      ? { title: 'Remision DLC', files: [file] }
      : { title: 'Remision DLC', text: 'Remision de despacho - Distribuciones Estrategicas de la Costa' };
    navigator.share(data).catch(function(e) { console.warn('share:', e); });
  }).catch(function() {
    btns.forEach(function(b) { b.style.display = ''; });
    element.style.minHeight = '';
    element.style.display = '';
    element.style.flexDirection = '';
    if (firmas) firmas.style.marginTop = '';
    showAdminToast('Error generando PDF');
  });
}
function doPrint() {
  var element = document.getElementById('remision-print');
  if (!element) { showAdminToast('❌ Error: No se encontró el contenido de la remisión'); return; }
  if (typeof html2pdf === 'undefined') { showAdminToast('❌ Error: Biblioteca html2pdf no cargada'); return; }
  var btns = document.querySelectorAll('.no-print');
  btns.forEach(function(btn) { btn.style.display = 'none'; });
  element.style.minHeight = '277mm';
  element.style.display = 'flex';
  element.style.flexDirection = 'column';
  var firmas = element.querySelector('.firmas-block');
  if (firmas) firmas.style.marginTop = 'auto';
  showAdminToast('Preparando impresión...');
  var opt = {
    margin: [10, 10, 10, 10],
    image: { type: 'jpeg', quality: 0.98 },
    html2canvas: { scale: 2, useCORS: true, logging: false, onclone: function(doc) { if (window.innerWidth < 800) { var ce = doc.getElementById('remision-print'); if (ce) { ce.style.width = '794px'; ce.style.maxWidth = '794px'; ce.style.minHeight = '277mm'; ce.style.display = 'flex'; ce.style.flexDirection = 'column'; var cf = ce.querySelector('.firmas-block'); if (cf) cf.style.marginTop = 'auto'; } } } },
    jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
  };
  html2pdf().set(opt).from(element).outputPdf('blob').then(function(blob) {
    btns.forEach(function(btn) { btn.style.display = ''; });
    element.style.minHeight = '';
    element.style.display = '';
    element.style.flexDirection = '';
    if (firmas) firmas.style.marginTop = '';
    var url = URL.createObjectURL(blob);
    var win = window.open(url);
    if (win) {
      win.addEventListener('load', function() {
        win.print();
        setTimeout(function() { URL.revokeObjectURL(url); }, 60000);
      });
    } else {
      URL.revokeObjectURL(url);
      showAdminToast('⚠️ Permite ventanas emergentes para imprimir');
    }
  }).catch(function(err) {
    console.error('Error al preparar impresión:', err);
    btns.forEach(function(btn) { btn.style.display = ''; });
    element.style.minHeight = '';
    element.style.display = '';
    element.style.flexDirection = '';
    if (firmas) firmas.style.marginTop = '';
    showAdminToast('❌ Error al preparar impresión');
  });
}
function doDownloadPDF(filename) {
  var element = document.getElementById('remision-print');
  if (!element) { showAdminToast('❌ Error: No se encontró el contenido de la remisión'); return; }
  if (typeof html2pdf === 'undefined') { showAdminToast('❌ Error: Biblioteca html2pdf no cargada'); return; }
  var btns = document.querySelectorAll('.no-print');
  btns.forEach(function(btn) { btn.style.display = 'none'; });
  element.style.minHeight = '277mm';


  element.style.display = 'flex';
  element.style.flexDirection = 'column';
  var firmas = element.querySelector('.firmas-block');
  if (firmas) firmas.style.marginTop = 'auto';
  showAdminToast('📄 Generando PDF...');
  var opt = {
    margin: [10, 10, 10, 10],
    filename: filename + '.pdf',
    image: { type: 'jpeg', quality: 0.98 },
    html2canvas: { scale: 2, useCORS: true, logging: false },
    jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
  };
  html2pdf().set(opt).from(element).save()
    .then(function() {
      btns.forEach(function(btn) { btn.style.display = ''; });
      element.style.minHeight = '';
      element.style.display = '';
      element.style.flexDirection = '';
      if (firmas) firmas.style.marginTop = '';
      showAdminToast('✅ PDF descargado: ' + filename + '.pdf');
    })
    .catch(function(err) {
      console.error('Error al generar PDF:', err);
      btns.forEach(function(btn) { btn.style.display = ''; });
      showAdminToast('❌ Error al generar PDF');
    });
}


function marcarEntregado(orderId) {
  if (!confirm('¿Confirmar que este pedido fue entregado al cliente?')) return;
  const o = orders.find(function(x) { return x.id === orderId; });
  if (o) { o.status = 'delivered'; addHistorial(orderId, 'delivered'); }
  updateOrderStatus(orderId, 'delivered').catch(function(e) { console.warn('supa delivered:', e); });
  renderLocalSection();
  showAdminToast('✅ Pedido ' + orderId + ' marcado como entregado.');
}
function doMarkDispatched(orderId) {
  if (!confirm('¿Confirmar que este pedido fue despachado?')) return;

  // Notificar al cliente por WhatsApp
  const order = orders.find(function(o) { return o.id === orderId; });
  if (order && order.phone) {
    const phone = order.phone.replace(/\D/g, '');
    const fullPhone = phone.startsWith('57') ? phone : '57' + phone;
    const msg = encodeURIComponent(
      '¡Hola ' + (order.client || order.cliente || '') + '! 🚚\n' +
      'Tu pedido *' + orderId + '* ha sido despachado y está en camino.\n' +
      'Pronto lo recibirás. ¡Gracias por confiar en Distribuciones Estratégicas! 📦'
    );
    window.open('https://wa.me/' + fullPhone + '?text=' + msg, '_blank');
  }

  // 1. Actualizar en memoria inmediatamente
  const o = orders.find(function(x) { return x.id === orderId; });
  if (o) { o.status = 'dispatched'; addHistorial(orderId, 'dispatched'); }

  // 2. Actualizar en Supabase
  updateOrderStatus(orderId, 'dispatched').catch(function(e) { console.warn('supa dispatch:', e); });
  closeModal('remision-modal');
  renderLocalSection();
  showAdminToast('🚚 Pedido ' + orderId + ' marcado como despachado.');
}

